refsection.programlisting:
load(GROCERDIR+'/data/gdpan_oecd.dat');
Y=explone(dblist(GROCERDIR+'/data/gdpan_oecd.dat'));
// extract matrix of data present in database
ADF_Individual(Y,0,%nan,5,0.05)
// provides the ADF test for all Y columns, with a constant but not trend (arg # 2 = 0),
// the Lag order to be determined by the programm (arg # 3 = %nan),
// the maximum number of lags set to 5(arg # 4 = 5), a 5% significance level (arg # 5 = 0.05).
